'use client';

import { SingleImageDrop } from '@/components/dropzone/single-image-drop';

interface AvatarDropzoneFieldProps {
    label?: string;
    description?: string;
    onFileSelect?: (file: File | null) => void;
    defaultImage?: string;
    maxSize?: number;
    className?: string;
}

export function AvatarDropzoneField({
    label,
    description,
    onFileSelect,
    defaultImage,
    maxSize = 5 * 1024 * 1024,
    className,
}: AvatarDropzoneFieldProps) {
    return (
        <SingleImageDrop
            variant="field"
            onFile={onFileSelect || (() => {})}
            maxSize={maxSize}
            preview={defaultImage}
            label={label || 'Upload Photo'}
            description={description}
            showRemoveButton={true}
            className={className}
        />
    );
}
